object Solution { def flood_fill(grid: Seq[Seq[Int]], sr: Int, sc: Int, newValue: Int): Seq[Seq[Int]] = { val out = grid.map(_.toArray).toArray; val old = out(sr)(sc); if (old == newValue) return out.map(_.toSeq).toSeq; val rows = out.length; val cols = out(0).length; val stack = scala.collection.mutable.Stack[(Int, Int)]((sr, sc)); while (stack.nonEmpty) { val (row, col) = stack.pop(); if (row >= 0 && row < rows && col >= 0 && col < cols && out(row)(col) == old) { out(row)(col) = newValue; stack.push((row + 1, col), (row - 1, col), (row, col + 1), (row, col - 1)) } }; out.map(_.toSeq).toSeq } }
